import{_ as o,c as i,o as a,ag as t}from"./chunks/framework.DVUBUV_u.js";const p=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[],"relativePath":"releases/2.4.0.md","filePath":"releases/2.4.0.md"}'),d={name:"releases/2.4.0.md"};function l(c,e,n,r,s,h){return a(),i("div",null,[...e[0]||(e[0]=[t('<h2 id="_2-4-0-2026-04-19" tabindex="-1">[2.4.0] - 2026-04-19 <a class="header-anchor" href="#_2-4-0-2026-04-19" aria-label="Permalink to &quot;[2.4.0] - 2026-04-19&quot;">​</a></h2><h3 id="network" tabindex="-1">Network <a class="header-anchor" href="#network" aria-label="Permalink to &quot;Network&quot;">​</a></h3><ul><li>The <code>Network</code> table now uses virtualization for better performance and reduced UI freezes.</li><li>The request details view now opens on the <code>Response</code> tab by default.</li><li>When a <code>Breakpoint</code> is triggered, the paused method automatically opens on the <code>Request</code> tab.</li><li>When <code>Pause</code> is enabled, inspector interceptors are detached, so native DevTools display the <code>original initiator</code> instead of <code>injected.ts</code>.</li><li><code>Search by</code> lists on the <code>Network</code> tab and in <code>Options</code> now support searching by the <code>Name</code> column.</li></ul><hr><h3 id="props" tabindex="-1">Props <a class="header-anchor" href="#props" aria-label="Permalink to &quot;Props&quot;">​</a></h3><ul><li><p><code>Props</code> performance has been significantly improved, making <code>auto refresh</code> safe to use.</p></li><li><p>In the <code>Props</code> table, the <code>Props</code> column has been split into <code>Passed</code> and <code>Declared</code> (all columns can be hidden):</p><ul><li><code>Passed</code> — number of props currently received;</li><li><code>Declared</code> — number of props declared on the component.</li></ul></li><li><p>In the right-side <code>Props details</code> panel, data is now split into two tabs:</p><ul><li><code>Passed</code> — props currently received (opened by default);</li><li><code>Declared</code> — all props declared by the component.</li></ul></li><li><p>The <code>Props details</code> panel now includes a <code>Size</code> parameter.</p></li></ul><h4 id="inspect-props-inspector" tabindex="-1">Inspect (Props Inspector) <a class="header-anchor" href="#inspect-props-inspector" aria-label="Permalink to &quot;Inspect (Props Inspector)&quot;">​</a></h4><ul><li>Added page element selection mode similar to <code>Chrome DevTools Elements</code>.</li><li>Allows selecting elements directly on the page for quick <code>Props</code> filtering.</li><li>Highlights <code>Vue</code> components on hover.</li><li>Displays quick element info: <code>Name</code>, <code>Root element</code>, <code>Received Props</code>, <code>Nested components</code>.</li><li>After selection, <code>Props</code> displays only the selected element and its nested components.</li><li>The filter can be quickly cleared via the <code>Filtered</code> badge.</li></ul><hr><h3 id="ui-ux" tabindex="-1">UI / UX <a class="header-anchor" href="#ui-ux" aria-label="Permalink to &quot;UI / UX&quot;">​</a></h3><h4 id="windowed-mode" tabindex="-1">Windowed mode <a class="header-anchor" href="#windowed-mode" aria-label="Permalink to &quot;Windowed mode&quot;">​</a></h4><ul><li>Added support for windowed mode with saved position for both launch modes.</li><li>Updated the iframe open chevron with a drag indicator.</li><li>Added support for docking the launcher to any of the four browser edges with automatic vertical stretching.</li></ul><h4 id="auto-launch-settings" tabindex="-1">Auto launch settings <a class="header-anchor" href="#auto-launch-settings" aria-label="Permalink to &quot;Auto launch settings&quot;">​</a></h4><ul><li><p>Added <code>Whitelist</code> for automatic app launch and <code>Blacklist</code> for excluded sites where launch and launcher display are disabled.</p></li><li><p>Added extension <code>popup</code> with quick actions:</p><ul><li><code>Forced Launch</code> — launches the app ignoring whitelist, blacklist, and static-site restrictions;</li><li><code>Reset Settings</code> — resets all extension settings.</li></ul></li></ul><h4 id="other-ui-improvements" tabindex="-1">Other UI improvements <a class="header-anchor" href="#other-ui-improvements" aria-label="Permalink to &quot;Other UI improvements&quot;">​</a></h4><ul><li>Fixed <code>JSON</code> styling for large data volumes.</li><li>Added exact search when entering values in quotes; without quotes, search works in <code>like</code> mode.</li><li>Minor visual interface improvements.</li><li>Improved <code>Esc</code> behavior in <code>DevTools</code> mode: first closes nested tabs, and when nothing else remains, opens the <code>DevTools Console</code>.</li></ul><hr><h3 id="performance" tabindex="-1">Performance <a class="header-anchor" href="#performance" aria-label="Permalink to &quot;Performance&quot;">​</a></h3><ul><li>Improved <code>Props</code> and <code>Store</code> detection mechanism for significantly faster data retrieval.</li><li>Increased limits for maximum readable <code>Props</code> count.</li><li>Refactored internal project structure: removed unused modules, dead code, and duplicated logic.</li></ul><hr><h3 id="documentation" tabindex="-1">Documentation <a class="header-anchor" href="#documentation" aria-label="Permalink to &quot;Documentation&quot;">​</a></h3><ul><li>Full project documentation has been added.</li><li>Added a <code>Documentation</code> section to the landing page.</li><li>Added quick documentation access via <code>Options → About</code>.</li></ul><hr><h3 id="fixes" tabindex="-1">Fixes <a class="header-anchor" href="#fixes" aria-label="Permalink to &quot;Fixes&quot;">​</a></h3><ul><li>Blocked native right-click menu inside the application context menu.</li><li>Improved search behavior in <code>DevTools mode</code>: fixed cases where search could stop working and added highlight reset when clearing the field or closing search.</li></ul>',25)])])}const m=o(d,[["render",l]]);export{p as __pageData,m as default};
